     1→/**
     2→ * @module V2SessionCoordinator
     3→ *
     4→ * The single, authoritative entry point for creating and managing
     5→ * Voice Engine V2 call sessions during the V1→V2 migration period.
     6→ *
     7→ * ## Responsibility
     8→ * `V2SessionCoordinator` owns the full lifecycle of a V2 session:
     9→ * creation, lookup-index attachment, retrieval, destruction, and
    10→ * periodic expiry cleanup. It delegates all storage concerns to
    11→ * `SessionRegistry` and all construction concerns to `SessionFactory`.
    12→ *
    13→ * ## What it does NOT do
    14→ * - No OpenAI calls.
    15→ * - No Exotel calls.
    16→ * - No transport or WebSocket logic.
    17→ * - No audio processing.
    18→ *
    19→ * ## Thread Safety
    20→ * Node.js is single-threaded. All methods are synchronous or sequential
    21→ * `async/await`. No locking is required.
    22→ *
    23→ * ## Rules
    24→ * - No OpenAI imports.
    25→ * - No Exotel imports.
    26→ * - No transport logic.
    27→ * - No WebSocket logic.
    28→ * - Owns ONLY `SessionRegistry`.
    29→ * - All dependencies injected through the constructor.
    30→ */
    31→
    32→import type { ILogger } from '../logger/index.js';
    33→import type { SessionId, CallSid, Nullable } from '../types/index.js';
    34→import type { ISessionRegistry } from './SessionRegistry.js';
    35→import type { ISessionFactory, CreateSessionParams } from './SessionFactory.js';
    36→import type { SessionContext } from './SessionContext.js';
    37→
    38→// ─── Options ──────────────────────────────────────────────────────────────────
    39→
    40→/**
    41→ * Configuration options for `V2SessionCoordinator`.
    42→ */
    43→export interface V2SessionCoordinatorOptions {
    44→  /**
    45→   * Maximum session age before it is eligible for cleanup.
    46→   * Defaults to 3 600 000 ms (1 hour).
    47→   */
    48→  readonly maxSessionAgeMs?: number;
    49→}
    50→
    51→// ─── Public Interface ─────────────────────────────────────────────────────────
    52→
    53→/**
    54→ * Public contract for the V2 session coordinator.
    55→ */
    56→export interface IV2SessionCoordinator {
    57→  /**
    58→   * Creates a new V2 call session.
    59→   *
    60→   * Internally calls `SessionFactory.createSession()` to construct all
    61→   * V2 engine dependencies, then registers the result in `SessionRegistry`.
    62→   *
    63→   * @param params - Session creation parameters (campaignId required; phone
    64→   *                 and callSid are optional at creation time).
    65→   * @returns The frozen `SessionContext` for the new session.
    66→   *
    67→   * @throws {Error} if session construction fails.
    68→   */
    69→  createSession(params: CreateSessionParams): Promise<Readonly<SessionContext>>;
    70→
    71→  /**
    72→   * Associates a telephony call SID with an existing session.
    73→   *
    74→   * Updates the `callSid` lookup index in `SessionRegistry` so that
    75→   * future calls to `getSession({ callSid })` resolve correctly.
    76→   *
    77→   * @param sessionId - The session to update.
    78→   * @param callSid   - The call SID returned by the telephony provider.
    79→   *
    80→   * @throws {Error} if `sessionId` is not registered.
    81→   */
    82→  attachCallSid(sessionId: SessionId, callSid: CallSid): void;
    83→
    84→  /**
    85→   * Associates a phone number with an existing session.
    86→   *
    87→   * Updates the `phone` lookup index in `SessionRegistry` so that
    88→   * future calls to `getSession({ phone })` resolve correctly.
    89→   *
    90→   * @param sessionId - The session to update.
    91→   * @param phone     - The E.164 phone number of the remote party.
    92→   *
    93→   * @throws {Error} if `sessionId` is not registered.
    94→   */
    95→  attachPhone(sessionId: SessionId, phone: string): void;
    96→
    97→  /**
    98→   * Retrieves a session by one of several lookup keys.
    99→   *
   100→   * Exactly one lookup key should be provided. If multiple are provided,
   101→   * `sessionId` takes precedence over `callSid`, which takes precedence
   102→   * over `phone`.
   103→   *
   104→   * @returns The `SessionContext`, or `null` if no match is found.
   105→   */
   106→  getSession(lookup: SessionLookup): Nullable<Readonly<SessionContext>>;
   107→
   108→  /**
   109→   * Destroys a session and releases all associated resources.
   110→   *
   111→   * Steps performed:
   112→   * 1. Retrieves the context from the registry.
   113→   * 2. Calls `voiceEngine.destroy()`.
   114→   * 3. Unregisters the session from `SessionRegistry`.
   115→   *
   116→   * No-op if the session is not found.
   117→   *
   118→   * @param sessionId - The session to destroy.
   119→   */
   120→  destroySession(sessionId: SessionId): void;
   121→
   122→  /**
   123→   * Removes all sessions older than the configured `maxSessionAgeMs`.
   124→   *
   125→   * Calls `voiceEngine.destroy()` on each removed session before
   126→   * unregistering it from the registry.
   127→   *
   128→   * @returns The number of sessions removed.
   129→   */
   130→  cleanupExpiredSessions(): number;
   131→
   132→  /**
   133→   * Returns the number of active sessions currently held in the registry.
   134→   */
   135→  readonly activeSessionCount: number;
   136→}
   137→
   138→// ─── Lookup Types ─────────────────────────────────────────────────────────────
   139→
   140→/**
   141→ * Identifies a session for retrieval.
   142→ * Provide exactly one field. Priority: sessionId > callSid > phone.
   143→ */
   144→export interface SessionLookup {
   145→  readonly sessionId?: SessionId;
   146→  readonly callSid?: CallSid;
   147→  readonly phone?: string;
   148→}
   149→
   150→// ─── Implementation ───────────────────────────────────────────────────────────
   151→
   152→/**
   153→ * Production implementation of `IV2SessionCoordinator`.
   154→ *
   155→ * Construct via `MigrationFactory.createCoordinator()`.
   156→ */
   157→export class V2SessionCoordinator implements IV2SessionCoordinator {
   158→  private readonly _log: ILogger;
   159→  private readonly _registry: ISessionRegistry;
   160→  private readonly _factory: ISessionFactory;
   161→  private readonly _maxSessionAgeMs: number;
   162→
   163→  /**
   164→   * @param registry - The session registry this coordinator owns.
   165→   * @param factory  - Factory used to construct new sessions.
   166→   * @param logger   - Logger; will be child-bound to this component.
   167→   * @param options  - Optional configuration overrides.
   168→   */
   169→  constructor(
   170→    registry: ISessionRegistry,
   171→    factory: ISessionFactory,
   172→    logger: ILogger,
   173→    options: V2SessionCoordinatorOptions = {}
   174→  ) {
   175→    this._registry       = registry;
   176→    this._factory        = factory;
   177→    this._log            = logger.child({ component: 'V2SessionCoordinator' });
   178→    this._maxSessionAgeMs = options.maxSessionAgeMs ?? 60 * 60 * 1000; // 1 hour
   179→  }
   180→
   181→  // ─── IV2SessionCoordinator ──────────────────────────────────────────────────
   182→
   183→  async createSession(
   184→    params: CreateSessionParams
   185→  ): Promise<Readonly<SessionContext>> {
   186→    this._log.info('Creating V2 session', {
   187→      campaignId: params.campaignId,
   188→      phone:      params.phone ?? null,
   189→      callSid:    params.callSid ?? null,
   190→    });
   191→
   192→    const context = await this._factory.createSession(params);
   193→    this._registry.register(context);
   194→
   195→    if (context.callSid) {
   196→      this._registry.updateCallSid(context.sessionId, context.callSid);
   197→    }
   198→
   199→    if (context.phone) {
   200→      this._registry.updatePhone(context.sessionId, context.phone);
   201→    }
   202→
   203→    this._log.info('V2 session created', {
   204→      sessionId:  context.sessionId,
   205→      campaignId: context.campaignId,
   206→    });
   207→
   208→    return context;
   209→  }
   210→
   211→  attachCallSid(sessionId: SessionId, callSid: CallSid): void {
   212→    this._log.debug('Attaching callSid', { sessionId, callSid });
   213→    this._registry.updateCallSid(sessionId, callSid);
   214→  }
   215→
   216→  attachPhone(sessionId: SessionId, phone: string): void {
   217→    this._log.debug('Attaching phone', { sessionId, phone });
   218→    this._registry.updatePhone(sessionId, phone);
   219→  }
   220→
   221→  getSession(lookup: SessionLookup): Nullable<Readonly<SessionContext>> {
   222→    if (lookup.sessionId !== undefined) {
   223→      return this._registry.get(lookup.sessionId);
   224→    }
   225→    if (lookup.callSid !== undefined) {
   226→      return this._registry.getByCallSid(lookup.callSid);
   227→    }
   228→    if (lookup.phone !== undefined) {
   229→      return this._registry.getByPhone(lookup.phone);
   230→    }
   231→
   232→    this._log.warn('getSession called with no lookup key');
   233→    return null;
   234→  }
   235→
   236→  destroySession(sessionId: SessionId): void {
   237→    const ctx = this._registry.get(sessionId);
   238→    if (!ctx) {
   239→      this._log.warn('destroySession: session not found', { sessionId });
   240→      return;
   241→    }
   242→
   243→    this._log.info('Destroying V2 session', { sessionId });
   244→
   245→    try {
   246→      ctx.voiceEngine.destroy();
   247→    } catch (err: unknown) {
   248→      const message = err instanceof Error ? err.message : String(err);
   249→      this._log.error('Error destroying voice engine', { sessionId, error: message });
   250→    }
   251→
   252→    this._registry.unregister(sessionId);
   253→    this._log.info('V2 session destroyed', { sessionId });
   254→  }
   255→
   256→  cleanupExpiredSessions(): number {
   257→    this._log.debug('Running expired session cleanup', {
   258→      maxSessionAgeMs: this._maxSessionAgeMs,
   259→      activeSessions:  this._registry.count(),
   260→    });
   261→
   262→    const cutoff = Date.now() - this._maxSessionAgeMs;
   263→
   264→    // Collect expired sessions first to avoid mutating the registry
   265→    // while iterating (unregister sweeps indices during unregister).
   266→    const expired = this._registry
   267→      .list()
   268→      .filter((ctx) => ctx.createdAt < cutoff)
   269→      .map((ctx) => ctx.sessionId);
   270→
   271→    for (const sessionId of expired) {
   272→      this.destroySession(sessionId);
   273→    }
   274→
   275→    if (expired.length > 0) {
   276→      this._log.info('Expired sessions cleaned up', {
   277→        removed:   expired.length,
   278→        remaining: this._registry.count(),
   279→      });
   280→    }
   281→
   282→    return expired.length;
   283→  }
   284→
   285→  get activeSessionCount(): number {
   286→    return this._registry.count();
   287→  }
   288→}
   289→

