     1→/**
     2→ * @module VoiceEngineFactory
     3→ *
     4→ * Top-level factory for constructing a fully wired `VoiceEngine`.
     5→ *
     6→ * ## Purpose
     7→ * `VoiceEngineFactory` is the SINGLE authoritative entry point for the
     8→ * entire engine assembly. It orchestrates:
     9→ * 1. Bootstrap — environment load, config merge, DI container construction.
    10→ * 2. Builder   — dependency graph assembly.
    11→ * 3. Engine    — lifecycle initialisation.
    12→ *
    13→ * ## Rules
    14→ * - No OpenAI SDK imports.
    15→ * - No Exotel protocol imports.
    16→ * - No Audio Engine internals.
    17→ * - No `process.env` (delegated entirely to the bootstrap layer).
    18→ * - No global singletons or static state.
    19→ * - All dependencies are injected.
    20→ *
    21→ * ## Usage
    22→ * ```typescript
    23→ * // Minimal usage — reads everything from environment variables.
    24→ * const factory = new VoiceEngineFactory();
    25→ * const engine = await factory.create();
    26→ *
    27→ * // With overrides:
    28→ * const engine = await factory.create({
    29→ *   bootstrapOptions: { providers: { logger: pinoLogger } },
    30→ *   builderOptions:   { gateway: myTestGateway },
    31→ *   autoStart:        true,
    32→ * });
    33→ * ```
    34→ */
    35→
    36→import { createVoiceEngineRuntime } from '../bootstrap/Bootstrap.js';
    37→import type { BootstrapOptions, VoiceEngineRuntime } from '../bootstrap/Bootstrap.js';
    38→import { VoiceEngineBuilder } from './VoiceEngineBuilder.js';
    39→import type { VoiceEngineBuilderOptions, IVoiceEngineBuilder } from './VoiceEngineBuilder.js';
    40→import type { IVoiceEngine } from './VoiceEngine.js';
    41→
    42→// ─── Factory Options ──────────────────────────────────────────────────────────
    43→
    44→/**
    45→ * Options for `VoiceEngineFactory.create()`.
    46→ */
    47→export interface VoiceEngineFactoryOptions {
    48→  /**
    49→   * Options forwarded to `createVoiceEngineRuntime()`.
    50→   * Use to inject concrete providers and config overrides.
    51→   */
    52→  readonly bootstrapOptions?: BootstrapOptions;
    53→
    54→  /**
    55→   * Options forwarded to the `VoiceEngineBuilder`.
    56→   * Use to override individual subsystems (e.g. in tests).
    57→   */
    58→  readonly builderOptions?: VoiceEngineBuilderOptions;
    59→
    60→  /**
    61→   * If `true`, `initialize()` and `start()` are called automatically before
    62→   * the engine is returned. Defaults to `false`.
    63→   *
    64→   * When `false`, the caller is responsible for calling
    65→   * `engine.initialize()` and `engine.start()` at the appropriate time.
    66→   */
    67→  readonly autoStart?: boolean;
    68→}
    69→
    70→// ─── Public Interface ─────────────────────────────────────────────────────────
    71→
    72→/**
    73→ * Public contract for the engine factory.
    74→ */
    75→export interface IVoiceEngineFactory {
    76→  /**
    77→   * Constructs, optionally initialises, and returns a `IVoiceEngine`.
    78→   *
    79→   * @param options - Bootstrap, builder, and lifecycle options.
    80→   * @returns A fully wired `IVoiceEngine`.
    81→   */
    82→  create(options?: VoiceEngineFactoryOptions): Promise<IVoiceEngine>;
    83→}
    84→
    85→// ─── Implementation ───────────────────────────────────────────────────────────
    86→
    87→/**
    88→ * Production implementation of `IVoiceEngineFactory`.
    89→ *
    90→ * Accepts an optional `IVoiceEngineBuilder` for testability.
    91→ */
    92→export class VoiceEngineFactory implements IVoiceEngineFactory {
    93→  private readonly _builder: IVoiceEngineBuilder;
    94→
    95→  constructor(builder: IVoiceEngineBuilder = new VoiceEngineBuilder()) {
    96→    this._builder = builder;
    97→  }
    98→
    99→  async create(options: VoiceEngineFactoryOptions = {}): Promise<IVoiceEngine> {
   100→    const runtime = this._buildRuntime(options.bootstrapOptions ?? {});
   101→    const engine = this._builder.build(runtime, options.builderOptions ?? {});
   102→
   103→    if (options.autoStart) {
   104→      await engine.initialize();
   105→      await engine.start();
   106→    }
   107→
   108→    return engine;
   109→  }
   110→
   111→  // ─── Private ───────────────────────────────────────────────────────────────
   112→
   113→  private _buildRuntime(bootstrapOptions: BootstrapOptions): VoiceEngineRuntime {
   114→    return createVoiceEngineRuntime(bootstrapOptions);
   115→  }
   116→}
   117→
   118→// ─── Convenience Function ─────────────────────────────────────────────────────
   119→
   120→/**
   121→ * Top-level convenience function for creating a `VoiceEngine`.
   122→ *
   123→ * Equivalent to `new VoiceEngineFactory().create(options)`.
   124→ *
   125→ * @param options - Bootstrap, builder, and lifecycle options.
   126→ * @returns A fully wired `IVoiceEngine`.
   127→ *
   128→ * @example
   129→ * ```typescript
   130→ * import { createVoiceEngine } from './voice-engine/engine/index.js';
   131→ *
   132→ * const engine = await createVoiceEngine({
   133→ *   bootstrapOptions: { providers: { logger } },
   134→ *   autoStart: true,
   135→ * });
   136→ *
   137→ * process.on('SIGTERM', () => {
   138→ *   engine.stop('sigterm').then(() => engine.destroy());
   139→ * });
   140→ * ```
   141→ */
   142→export async function createVoiceEngine(
   143→  options: VoiceEngineFactoryOptions = {}
   144→): Promise<IVoiceEngine> {
   145→  return new VoiceEngineFactory().create(options);
   146→}
