     1→/**
     2→ * @module VoiceEngine
     3→ *
     4→ * The top-level coordinator of Voice Engine V2.
     5→ *
     6→ * ## Purpose
     7→ * `VoiceEngine` is the single owner and lifecycle manager of all subsystems.
     8→ * It wires bootstrap, transport, media, and provider resolution together
     9→ * through `VoiceEngineLifecycle`, `VoiceEngineHealth`, and `VoiceEngineEvents`
    10→ * without containing any business logic, provider-specific code, or protocol
    11→ * knowledge.
    12→ *
    13→ * ## Ownership
    14→ * The `VoiceEngine` owns:
    15→ * - The bootstrap `VoiceEngineRuntime` (config + DI container + resolver).
    16→ * - The `ITransportGateway` (all WebSocket connections).
    17→ * - The `IMediaSessionFactory` (per-call session construction).
    18→ * - The `HealthRegistry` (provider health callbacks).
    19→ * - The `VoiceEngineLifecycle` (state machine).
    20→ * - The `VoiceEngineHealth` (aggregated health reporting).
    21→ * - The `IVoiceEngineEventBus` (lifecycle event fan-out).
    22→ *
    23→ * ## Lifecycle
    24→ * ```
    25→ * VoiceEngine.initialize()   → INITIALIZING → READY
    26→ * VoiceEngine.start()        → READY        → RUNNING
    27→ * VoiceEngine.stop(reason)   → RUNNING      → STOPPING → STOPPED
    28→ * VoiceEngine.destroy()      → (any)        → DESTROYED
    29→ * ```
    30→ *
    31→ * ## Rules
    32→ * - No OpenAI SDK imports.
    33→ * - No Exotel protocol imports.
    34→ * - No Audio Engine internals.
    35→ * - Communicates with subsystems ONLY through public interfaces.
    36→ * - No `process.env`.
    37→ * - No global singletons or static state.
    38→ * - No business logic.
    39→ */
    40→
    41→import type { VoiceEngineRuntime } from '../bootstrap/Bootstrap.js';
    42→import type { ITransportGateway } from '../transport/TransportGateway.js';
    43→import type { IMediaSessionFactory } from '../media/MediaSessionFactory.js';
    44→import type { ILogger } from '../logger/index.js';
    45→import type { ReadyStatus } from '../monitoring/index.js';
    46→import type { Timestamp } from '../types/index.js';
    47→import { VoiceEngineLifecycle } from './VoiceEngineLifecycle.js';
    48→import type { VoiceEngineLifecycleState } from './VoiceEngineLifecycle.js';
    49→import type { IVoiceEngineHealth, EngineHealthReport } from './VoiceEngineHealth.js';
    50→import type {
    51→  IVoiceEngineEventBus,
    52→  VoiceEngineEventType,
    53→  VoiceEngineEventMap,
    54→  VoiceEngineEventHandler,
    55→} from './VoiceEngineEvents.js';
    56→
    57→// ─── Engine ID ────────────────────────────────────────────────────────────────
    58→
    59→let _engineCounter = 0;
    60→
    61→function nextEngineId(): string {
    62→  return `ve-${Date.now()}-${++_engineCounter}`;
    63→}
    64→
    65→// ─── Public Interface ─────────────────────────────────────────────────────────
    66→
    67→/**
    68→ * Public contract for the Voice Engine.
    69→ */
    70→export interface IVoiceEngine {
    71→  /** Unique identifier for this engine instance. */
    72→  readonly engineId: string;
    73→
    74→  /** Current lifecycle state. */
    75→  readonly state: VoiceEngineLifecycleState;
    76→
    77→  /** Whether the engine is actively serving calls. */
    78→  readonly isRunning: boolean;
    79→
    80→  /** Monotonic timestamp when the engine entered the current state. */
    81→  readonly stateEnteredAt: Timestamp;
    82→
    83→  /**
    84→   * Initialises all subsystems and transitions to the READY state.
    85→   *
    86→   * Must be called before `start()`. Idempotent if already READY.
    87→   *
    88→   * @throws {Error} if the engine is in a terminal state.
    89→   * @throws {Error} if initialisation fails (transitions to FAILED).
    90→   */
    91→  initialize(): Promise<void>;
    92→
    93→  /**
    94→   * Starts the engine, opening the transport gateway to inbound connections.
    95→   * Transitions from READY → RUNNING.
    96→   *
    97→   * @throws {Error} if the engine is not in the READY state.
    98→   */
    99→  start(): Promise<void>;
   100→
   101→  /**
   102→   * Gracefully stops the engine.
   103→   *
   104→   * 1. Stops accepting new connections.
   105→   * 2. Drains active calls up to `drainTimeoutMs`.
   106→   * 3. Transitions to STOPPED.
   107→   *
   108→   * @param reason        - Human-readable stop reason.
   109→   * @param drainTimeoutMs - Maximum milliseconds to wait for call drain (default 30 000).
   110→   */
   111→  stop(reason?: string, drainTimeoutMs?: number): Promise<void>;
   112→
   113→  /**
   114→   * Performs a full shutdown and releases all resources.
   115→   * May be called from any state. Always transitions to DESTROYED.
   116→   * Safe to call multiple times (idempotent).
   117→   */
   118→  destroy(): void;
   119→
   120→  /**
   121→   * Returns an aggregated health report for all subsystems.
   122→   */
   123→  getHealthReport(): Promise<Readonly<EngineHealthReport>>;
   124→
   125→  /**
   126→   * Returns the current provider ready status from the health registry.
   127→   */
   128→  getReadyStatus(): Promise<ReadyStatus>;
   129→
   130→  /** Subscribes to a lifecycle event type. */
   131→  on<T extends VoiceEngineEventType>(
   132→    type: T,
   133→    handler: VoiceEngineEventHandler<VoiceEngineEventMap[T]>
   134→  ): void;
   135→
   136→  /** Unsubscribes from a lifecycle event type. */
   137→  off<T extends VoiceEngineEventType>(
   138→    type: T,
   139→    handler: VoiceEngineEventHandler<VoiceEngineEventMap[T]>
   140→  ): void;
   141→}
   142→
   143→// ─── Dependencies ─────────────────────────────────────────────────────────────
   144→
   145→/**
   146→ * All dependencies required to construct a `VoiceEngine`.
   147→ *
   148→ * Assembled by `VoiceEngineBuilder`. Every field is required and fully
   149→ * initialised before being passed to the constructor.
   150→ */
   151→export interface VoiceEngineDependencies {
   152→  /** The bootstrap runtime (config, DI container, resolver, health registry). */
   153→  readonly runtime: VoiceEngineRuntime;
   154→  /** The transport gateway that owns all WebSocket connections. */
   155→  readonly gateway: ITransportGateway;
   156→  /** Factory for constructing per-call MediaSessions. */
   157→  readonly mediaSessionFactory: IMediaSessionFactory;
   158→  /** Health aggregator for all subsystems. */
   159→  readonly health: IVoiceEngineHealth;
   160→  /** Lifecycle event bus. */
   161→  readonly eventBus: IVoiceEngineEventBus;
   162→  /** Structured logger, bound with engine context. */
   163→  readonly logger: ILogger;
   164→}
   165→
   166→// ─── Implementation ───────────────────────────────────────────────────────────
   167→
   168→/**
   169→ * Production implementation of `IVoiceEngine`.
   170→ */
   171→export class VoiceEngine implements IVoiceEngine {
   172→  readonly engineId: string;
   173→
   174→  private readonly _runtime: VoiceEngineRuntime;
   175→  private readonly _gateway: ITransportGateway;
   176→  private readonly _mediaSessionFactory: IMediaSessionFactory;
   177→  private readonly _health: IVoiceEngineHealth;
   178→  private readonly _eventBus: IVoiceEngineEventBus;
   179→  private readonly _logger: ILogger;
   180→  private readonly _lifecycle: VoiceEngineLifecycle;
   181→
   182→  private _startedAt: Timestamp = 0;
   183→
   184→  constructor(deps: VoiceEngineDependencies) {
   185→    this.engineId = nextEngineId();
   186→    this._runtime = deps.runtime;
   187→    this._gateway = deps.gateway;
   188→    this._mediaSessionFactory = deps.mediaSessionFactory;
   189→    this._health = deps.health;
   190→    this._eventBus = deps.eventBus;
   191→    this._logger = deps.logger.child({ component: 'VoiceEngine', engineId: this.engineId });
   192→    this._lifecycle = new VoiceEngineLifecycle('INITIALIZING');
