    29→
    30→// ─── Console Logger Adapter ───────────────────────────────────────────────────
    31→
    32→/**
    33→ * Minimal `ILogger` implementation backed by `console`.
    34→ * Used for the migration layer until a structured logger is wired into the
    35→ * bootstrap. Child bindings are merged into every log line as JSON context.
    36→ */
    37→function createConsoleLogger(bindings: LogContext = {}): ILogger {
    38→  const prefix = Object.keys(bindings).length
    39→    ? ` ${JSON.stringify(bindings)}`
    40→    : '';
    41→
    42→  const fmt = (level: string, message: string, ctx?: LogContext): string => {
    43→    const ctxStr = ctx && Object.keys(ctx).length ? ` ${JSON.stringify(ctx)}` : '';
    44→    return `[V2Migration${prefix}] [${level.toUpperCase()}] ${message}${ctxStr}`;
    45→  };
    46→
    47→  return {
    48→    debug: (message, ctx) => console.debug(fmt('debug', message, ctx)),
    49→    info:  (message, ctx) => console.info(fmt('info',  message, ctx)),
    50→    warn:  (message, ctx) => console.warn(fmt('warn',  message, ctx)),
    51→    error: (message, ctx) => console.error(fmt('error', message, ctx)),
    52→    child: (childBindings) =>
    53→      createConsoleLogger({ ...bindings, ...childBindings }),
    54→  };
    55→}
    56→
    57→// ─── Singleton ────────────────────────────────────────────────────────────────
    58→
    59→let _coordinator: IV2SessionCoordinator | null = null;
