    65→ *
    66→ * Lazy-initialises on first call. Thread-safe in Node.js single-threaded
    67→ * runtime — no race condition is possible.
    68→ *
    69→ * @returns The singleton coordinator.
    70→ */
    71→export function getV2Coordinator(): IV2SessionCoordinator {
    72→  if (_coordinator) return _coordinator;
    73→
    74→  const logger = createConsoleLogger({ subsystem: 'V2SessionCoordinator' });
    75→
    76→  logger.info('Initialising V2SessionCoordinator singleton');
    77→
    78→  _coordinator = createV2SessionCoordinator(
