    80→      voiceEngineFactory: new VoiceEngineFactory(),
    81→      transportFactory:   new TransportFactory(logger),
    82→      logger,
    83→    },
    84→    {
    85→      coordinator: {
    86→        maxSessionAgeMs: 2 * 60 * 60 * 1000, // 2 hours
    87→      },
    88→    }
    89→  );
    90→
    91→  logger.info('V2SessionCoordinator ready', {
    92→    activeSessions: _coordinator.activeSessionCount,
    93→  });
    94→
    95→  return _coordinator;
    96→}
    97→
    98→/**
    99→ * Destroys all active V2 sessions and releases the singleton.
   100→ *
   101→ * Call during process shutdown (SIGTERM / SIGINT) to ensure no sessions
   102→ * are leaked. After this call, the next `getV2Coordinator()` will
   103→ * reinitialise a fresh coordinator.
   104→ */
   105→export function destroyV2Coordinator(): void {
   106→  if (!_coordinator) return;
   107→
   108→  const logger = createConsoleLogger({ subsystem: 'V2SessionCoordinator' });
   109→  const active = _coordinator.activeSessionCount;
   110→
